import sys

def solve(data: str) -> str:
    words = data.split()
    counts: dict[str, int] = {}
    for word in words:
        counts[word] = counts.get(word, 0) + 1
    count_line = ' '.join(f"{word}={counts[word]}" for word in sorted(counts))
    unique_line = ' '.join(sorted(set(words)))
    return f"{count_line}\n{unique_line}"

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
